-- FSI_DEMO_DB.BANKING.CUSTOMER_INTERACTIONS

CREATE OR REPLACE TABLE FSI_DEMO_DB.BANKING.CUSTOMER_INTERACTIONS (

    INTERACTION_ID VARCHAR(20) NOT NULL,
    CUSTOMER_ID VARCHAR(20),
    INTERACTION_DATE TIMESTAMP_NTZ(9),
    CHANNEL VARCHAR(30),
    INTERACTION_TYPE VARCHAR(50),
    AGENT_ID VARCHAR(20),
    DURATION_SECONDS NUMBER(10,0),
    TRANSCRIPT VARCHAR(16777216),
    SUMMARY VARCHAR(1000),
    ISSUE_CATEGORY VARCHAR(50),
    RESOLUTION_STATUS VARCHAR(30),
    SENTIMENT_SCORE NUMBER(5,4),
    SENTIMENT_LABEL VARCHAR(20),
    CSAT_SCORE NUMBER(2,0),
    FIRST_CONTACT_RESOLUTION BOOLEAN,
    ESCALATED BOOLEAN DEFAULT FALSE,
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (INTERACTION_ID)

);





