INSERT INTO FSI_DEMO_DB.BANKING.CUSTOMER_INTERACTIONS (INTERACTION_ID, CUSTOMER_ID, INTERACTION_DATE, CHANNEL, INTERACTION_TYPE, AGENT_ID, DURATION_SECONDS, TRANSCRIPT, SUMMARY, ISSUE_CATEGORY, RESOLUTION_STATUS, SENTIMENT_SCORE, SENTIMENT_LABEL, CSAT_SCORE, FIRST_CONTACT_RESOLUTION, ESCALATED, CREATED_AT) VALUES
('INT00002000', 'CUST00002000', '2026-01-25 10:51:36.881', 'PHONE', 'INQUIRY', 'AGT00000', '520', 'Customer: I need help setting up automatic bill payments. Agent: Id be happy to help you set that up. Which bills would you like to automate? Customer: My utilities and car payment. Agent: Perfect. Let me walk you through the process step by step. First, lets start with your utility company.', 'Set up automatic bill payments for utilities and car payment', 'FRAUD_DISPUTE', 'PENDING', '0.4000', 'NEUTRAL', '1', FALSE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002001', 'CUST00002001', '2026-01-25 10:34:56.881', 'CHAT', 'COMPLAINT', 'AGT00001', '537', 'Customer: Why was I charged an overdraft fee? I had money in my account! Agent: I understand your frustration. Let me review your account. I see that a large debit posted before your deposit cleared. Customer: That seems unfair. Agent: I agree this situation is frustrating. As a one-time courtesy, I can waive this fee for you. Customer: Thank you, I appreciate that.', 'Waived overdraft fee as one-time courtesy after explanation', 'TECHNICAL_SUPPORT', 'ESCALATED', '-0.3900', 'NEGATIVE', NULL, FALSE, TRUE, '2026-02-17 14:24:56.881'),
('INT00002002', 'CUST00002002', '2026-01-25 10:18:16.881', 'EMAIL', 'SUPPORT', 'AGT00002', '554', 'Customer: Im interested in opening a savings account for my child. Agent: Thats wonderful! We have several youth savings options with great benefits. The Junior Saver account has no monthly fees and earns competitive interest. Customer: That sounds perfect. What do I need to open it? Agent: Just bring your childs birth certificate and social security card to any branch.', 'Provided information on youth savings account options', 'CREDIT_REQUEST', 'RESOLVED', '0.4200', 'NEUTRAL', '5', TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002003', 'CUST00002003', '2026-01-25 10:01:36.881', 'BRANCH', 'TRANSACTION_DISPUTE', 'AGT00003', '571', 'Customer: I have a question about wire transfers. Agent: Of course, I can help with that. Are you sending domestically or internationally? Customer: International to Canada. Agent: For international wires, we need the recipients bank SWIFT code and IBAN. The fee is $45 and typically arrives within 1-2 business days. Would you like to proceed?', 'Explained international wire transfer process and fees', 'LOAN_INQUIRY', 'RESOLVED', '0.4300', 'NEUTRAL', '2', TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002004', 'CUST00002004', '2026-01-25 09:44:56.881', 'MOBILE_APP', 'ACCOUNT_CHANGE', 'AGT00004', '588', 'Customer: Hi, I noticed a charge on my account that I dont recognize for $54. Agent: I understand your concern. Let me look into that for you. I can see the charge was from a subscription service. Would you like me to help you dispute this? Customer: Yes please, I never signed up for that. Agent: Ive initiated a dispute and temporary credit. You should see it within 24 hours.', 'Customer disputed unrecognized charge, dispute initiated with temporary credit', 'CARD_SERVICES', 'RESOLVED', '0.4400', 'NEUTRAL', NULL, TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002005', 'CUST00002005', '2026-01-25 09:28:16.881', 'PHONE', 'PRODUCT_INQUIRY', 'AGT00005', '605', 'Customer: Im very frustrated with your service. This is the third time Ive called about the same issue with my online banking. Agent: I sincerely apologize for the inconvenience. Let me escalate this to our technical team right away. Customer: I just want it fixed. Agent: I completely understand. Ive created a priority ticket and you will receive a call back within 2 hours.', 'Escalated recurring technical issue with online banking to priority support', 'DIGITAL_BANKING', 'RESOLVED', '-0.5500', 'NEGATIVE', '6', TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002006', 'CUST00002006', '2026-01-25 09:11:36.881', 'CHAT', 'FEEDBACK', 'AGT00006', '622', 'Customer: I want to increase my credit limit. Agent: Id be happy to help with that. Based on your account history, you may qualify for an increase. Let me check your eligibility. Customer: That would be great. Agent: Good news! You qualify for a $5,000 increase. Would you like me to process that? Customer: Yes, thank you so much!', 'Approved credit limit increase of $5,000 based on account eligibility', 'ACCOUNT_CLOSURE', 'RESOLVED', '0.4600', 'NEUTRAL', '3', TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002007', 'CUST00002007', '2026-01-25 08:54:56.881', 'EMAIL', 'GENERAL', 'AGT00007', '639', 'Customer: Can you help me understand my mortgage options? Agent: Absolutely! Based on current rates, we have several programs available. Are you looking to purchase or refinance? Customer: Refinance my current home. Agent: With your credit profile, you could potentially save around $300 per month. Would you like me to connect you with our mortgage specialist?', 'Discussed mortgage refinance options, referred to mortgage specialist', 'FEEDBACK', 'RESOLVED', '0.4700', 'NEUTRAL', NULL, TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002008', 'CUST00002008', '2026-01-25 08:38:16.881', 'BRANCH', 'INQUIRY', 'AGT00008', '656', 'Customer: I need to report my card stolen. Agent: Im sorry to hear that. Let me immediately block your current card and issue a replacement. Have you noticed any unauthorized transactions? Customer: Not yet but I want to be safe. Agent: Smart thinking. Your new card will arrive in 3-5 business days. Is there anything else I can help with?', 'Reported stolen card, blocked immediately and ordered replacement', 'PAYMENTS', 'RESOLVED', '0.4800', 'NEUTRAL', '7', TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002009', 'CUST00002009', '2026-01-25 08:21:36.881', 'MOBILE_APP', 'COMPLAINT', 'AGT00009', '673', 'Customer: Your mobile app keeps crashing when I try to deposit checks. Agent: I apologize for the technical difficulties. Can you tell me what device youre using? Customer: iPhone 14. Agent: There is a known issue we are working to fix. In the meantime, I can process a temporary workaround. Would you like me to walk you through it?', 'Troubleshot mobile app check deposit issue, provided workaround', 'FEES', 'RESOLVED', '0.4900', 'NEUTRAL', '4', TRUE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002010', 'CUST00002010', '2026-01-25 08:04:56.881', 'PHONE', 'SUPPORT', 'AGT00010', '690', 'Customer: I want to close my account. Agent: Im sorry to hear that. May I ask what prompted this decision? Customer: Ive found better rates elsewhere. Agent: I understand. Before you go, I wanted to let you know about our loyalty program that offers competitive rates. Would you be interested in hearing more? Customer: Okay, tell me about it.', 'Retention conversation for account closure, presented loyalty program', 'FRAUD_DISPUTE', 'PENDING', '-0.3000', 'NEGATIVE', NULL, FALSE, FALSE, '2026-02-17 14:24:56.881'),
('INT00002011', 'CUST00002011', '2026-01-25 07:48:16.881', 'CHAT', 'TRANSACTION_DISPUTE', 'AGT00011', '707', 'Customer: Thank you for the excellent service last week. Your representative Sarah was incredibly helpful. Agent: Thank you so much for taking the time to share that feedback! I will make sure Sarah and her manager know about your kind words. Is there anything else I can assist you with today?', 'Positive feedback received for representative Sarah', 'TECHNICAL_SUPPORT', 'ESCALATED', '0.9100', 'POSITIVE', '8', FALSE, TRUE, '2026-02-17 14:24:56.881'),
